CREATE TABLE `enrollments` (
  `id` int NOT NULL AUTO_INCREMENT,
  `student_username` varchar(50) NOT NULL,
  `offering_id` int NOT NULL,
  `status` enum('ENROLLED','DROPPED') NOT NULL DEFAULT 'ENROLLED',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_enrollment` (`student_username`,`offering_id`),
  KEY `fk_enrollments_offering` (`offering_id`),
  CONSTRAINT `fk_enrollments_offering` FOREIGN KEY (`offering_id`) REFERENCES `course_offerings` (`id`),
  CONSTRAINT `fk_enrollments_student` FOREIGN KEY (`student_username`) REFERENCES `students` (`username`)
) ENGINE=InnoDB AUTO_INCREMENT=767 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
