--
-- Table structure for table `grade_records`
--

DROP TABLE IF EXISTS `grade_records`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `grade_records` (
  `id` int NOT NULL AUTO_INCREMENT,
  `student_username` varchar(50) NOT NULL,
  `offering_id` int NOT NULL,
  `attendance_mark` decimal(5,2) DEFAULT '0.00',
  `class_test_mark` decimal(5,2) DEFAULT '0.00',
  `assignment_mark` decimal(5,2) DEFAULT '0.00',
  `mid_mark` decimal(5,2) DEFAULT '0.00',
  `final_mark` decimal(5,2) DEFAULT '0.00',
  `total_mark` decimal(6,2) DEFAULT '0.00',
  `letter_grade` varchar(5) DEFAULT NULL,
  `grade_point` decimal(3,2) DEFAULT NULL,
  `published` tinyint(1) NOT NULL DEFAULT '0',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_grade` (`student_username`,`offering_id`),
  KEY `fk_grade_offering` (`offering_id`),
  CONSTRAINT `fk_grade_offering` FOREIGN KEY (`offering_id`) REFERENCES `course_offerings` (`id`),
  CONSTRAINT `fk_grade_student` FOREIGN KEY (`student_username`) REFERENCES `students` (`username`)
) ENGINE=InnoDB AUTO_INCREMENT=1088 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

